output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?show ?showLabel ?startDate WHERE {
  ?show wdt:P161 wd:Q926963 .
  OPTIONAL {
    ?show wdt:P577 ?startDate
  }
  .
  OPTIONAL {
    ?show rdfs:label ?showLabel
    FILTER(LANG(?showLabel) = "en")
  }
}
ORDER BY ASC(?startDate)
LIMIT 1

args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?show ?showLabel ?date
WHERE {
  ?character wdt:P3113 wd:Q926963.
  ?character wdt:P1723 ?show.
  ?show wdt:P31 wd:Q5398426.
  OPTIONAL { ?show wdt:P577 ?date }
  OPTIONAL { ?show rdfs:label ?showLabel FILTER(LANG(?showLabel) = "en") }
}
ORDER BY ASC(?date)
LIMIT 1

